#include <stdio.h>

int countzeroes(int x, int s[])
{
	int count=0;
	for(int j=0;j<=x;j++){
		if(s[j]==0)
			count++;
	}
	return count;
}

int countones(int x, int s[])
{
	int count=0;
	for(int j=0;j<=x;j++){
		if(s[j]==1)
			count++;
	}
	return count;
}

int main(void) {
	int n,i;  //n is the total number of games.
	scanf("%d",&n);

	int s[n];
	for(i=0;i<n;i++)
		scanf("%d",&s[i]);

	/*for(i=0;i<n;i++)
		printf("%d",s[i]); */

	int zeroes,ones;
	zeroes=countzeroes(n-1,s);
	ones=countones(n-1,s);

	int zero[zeroes],x,y,counter=0;
	for(i=0;i<n;i++){
		if(s[i]==0){
			x=countzeroes(i,s);
			y=ones-countones(i,s);
			//printf("%d %d   %d\n",x,y,x+y);
			zero[counter]=x+y;
			counter++;
		}
	}

	/*for(i=0;i<zeroes;i++)
		printf("%d",zero[i]);
	printf("\n");*/

	int ans;
	if(zeroes>ones)
		ans=zeroes;
	else
		ans=ones;

	//printf("ans is %d \n", ans);

	for(i=0;i<zeroes;i++){
		if(zero[i]>ans)
			ans=zero[i];
	}

	printf("%d\n", ans);
	return 0;
}

