use std::io;

fn main() {
    let n: usize = {
        let mut input = String::new();
        io::stdin().read_line(&mut input).unwrap();
        input.trim().parse().unwrap()
    };

    let a: Vec<u8> = {
        let mut input = String::new();
        io::stdin().read_line(&mut input).unwrap();
        input.split_whitespace().map(|k| k.parse().unwrap()).collect()
    };

    let mut prefix_sums: Vec<_> = a.iter().scan(0, |state, &k| {
        if k == 1 {
            *state += 1;
        }
        Some(*state)
    }).collect();

    prefix_sums.insert(0, 0);

    let mut b = a.clone();

    b.reverse();

    let mut suffix_sums: Vec<_> = b.iter().scan(0, |state, &k| {
        if k == 0 {
            *state += 1;
        }
        Some(*state)
    }).collect();

    suffix_sums.insert(0, 0);

    suffix_sums.reverse();

    let ans = (0..n + 1).map(|i| prefix_sums[i] + suffix_sums[i]).min().unwrap();

    println!("{}", n - ans);
}
